def validate_message_match(ad_hook: str, landing_headline: str) -> dict: """Check message match between ad and landing page.""" # Extract key terms from both ad_terms = set(ad_hook.lower().split()) landing_terms = set(landing_headline.lower().split())
overlap = ad_terms.intersection(landing_terms) match_score = len(overlap) / max(len(ad_terms), 1)
return { "passed": match_score >= 0.4, "match_score": round(match_score, 2), "overlapping_terms": list(overlap), "recommendation": "Align key terms between ad hook and landing headline" if match_score < 0.4 else None }


def validate_funnel_structure(funnel: dict) -> dict:
    """Validate 3-page funnel structure."""
    required_pages = ["opt_in", "offer", "upsell"]
    required_elements = {
        "opt_in": ["headline", "subhead", "bullets", "cta"],
        "offer": ["hook", "value_delivery", "offer_presentation", "cta"],
        "upsell": ["offer", "cta"]
    }

    issues = []
    for page in required_pages:
        if page not in funnel:
            issues.append(f"Missing page: {page}")
            continue

        page_content = funnel[page]
        for element in required_elements.get(page, []):
            if element not in page_content:
                issues.append(f"{page}: Missing {element}")

    return {
        "passed": len(issues) == 0,
        "pages_present": [p for p in required_pages if p in funnel],
        "issues": issues
    }


def validate_tracking_setup(tracking: dict) -> dict:
    """Validate tracking configuration."""
    required_events = ["page_view", "opt_in", "offer_view", "cta_click"]
    required_fields = ["utm_schema", "crm_fields"]

    issues = []

    events = tracking.get("events", [])
    missing_events = [e for e in required_events if e not in [ev.get("name") for ev in events]]
    if missing_events:
        issues.append(f"Missing events: {missing_events}")

    for field in required_fields:
        if field not in tracking:
            issues.append(f"Missing: {field}")

    return {
        "passed": len(issues) == 0,
        "events_count": len(events),
        "issues": issues,
        "warning": "Never run paid traffic without tracking" if issues else None
    }
